4	import { Expandable } from "../../components/expandable";
5	import { MetaAside } from "../../components/meta-aside";
6	import { DraggableList } from "./draggable-list";
7	import { Nudges } from "./nudges";
8	import { RalphEssay } from "./ralph-essay";
9	import { TestDiff } from "./test-diff";
10	import { Transcript } from "./transcript";
11	import { useClaimTracker } from "./use-claim-tracker";
12	
13	const RALPH_ASIDE =
14	  "The Ralph loop: keep handing the agent its unfinished work until it earns the exit phrase. The agent's \"done\" is cheap. The loop's exit condition isn't.";
15	
16	export function Completion() {
17	  const tracker = useClaimTracker();
18	  const [hasDragged, setHasDragged] = useState(false);
19	  const [remountKey, setRemountKey] = useState(0);
20	
21	  const handleDragPerformed = useCallback(() => {
22	    setHasDragged(true);
23	  }, []);
24	
25	  const handleReorderFailed = useCallback(() => {
26	    tracker.markCaught("optimistic");
