import { cn } from "@repo/design-system/lib/utils";
import type { Stage } from "./stage";

const NUDGES: readonly { id: Stage; text: string }[] = [
  { id: "sent", text: "Send the renewal request." },
  { id: "aged", text: "Advance the clock 12 months." },
  { id: "revealed", text: "See what the validation actually did." },
];

const ORDER: readonly Stage[] = ["initial", "sent", "aged", "revealed"];

interface NudgesProps {
  stage: Stage;
}

export function Nudges({ stage }: NudgesProps) {
  const reachedIndex = ORDER.indexOf(stage);

  return (
    <div className="rounded-md border border-border/50 bg-foreground/[0.015] p-4 dark:bg-foreground/[0.025]">
      <p className="mb-2 font-medium font-mono text-[0.7rem] text-foreground/55 uppercase tracking-[0.2em]">
        Try this
      </p>
      <ul className="space-y-1.5 text-sm">
        {NUDGES.map((nudge) => {
          const targetIndex = ORDER.indexOf(nudge.id);
          const reached = reachedIndex >= targetIndex;
          return (
            <li
              className={cn(
                "flex items-baseline gap-2 transition-colors",
                reached ? "text-foreground/35" : "text-foreground/75"
              )}
              key={nudge.id}
            >
              <span
                aria-hidden="true"
                className={cn(
                  "select-none",
                  reached
                    ? "text-emerald-600 dark:text-emerald-400"
                    : "text-foreground/40"
                )}
              >
                {reached ? "✓" : "○"}
              </span>
              <span className={cn(reached && "line-through")}>
                {nudge.text}
              </span>
            </li>
          );
        })}
      </ul>
    </div>
  );
}

