import { cn } from "@repo/design-system/lib/utils";
import type { Stage } from "./stage";

interface PipelineProps {
  stage: Stage;
}

const PROFILE_ID = "p_8c4f";
const PROFILE_NAME = "Eric Stolz";
const ORIGINAL_CREATED_AT = "2025-04-22T09:14:00Z";
const COERCED_CREATED_AT = "1970-01-01T00:00:00Z";

export function Pipeline({ stage }: PipelineProps) {
  const sent = stage !== "initial";
  const deleted = stage === "aged" || stage === "revealed";

  return (
    <div className="grid gap-4 md:grid-cols-3">
      <Panel label="Request">
        <pre className="font-mono text-foreground/80 text-xs leading-6">
          <span className="block text-foreground/55">
            PATCH /profiles/{PROFILE_ID}
          </span>
          <span className="block">{`{`}</span>
          <span className="block">{`  "name": "${PROFILE_NAME}"`}</span>
          <span className="block text-foreground/45">
            {"  // no createdAt — keep existing"}
          </span>
          <span className="block">{`}`}</span>
        </pre>
      </Panel>

      <Panel label="Validation">
        <pre className="font-mono text-foreground/80 text-xs leading-6">
          <span className="block text-foreground/55">{"// schema.ts"}</span>
          <span className="block">{`z.object({`}</span>
          <span className="block">
            {"  createdAt: z.coerce.date()"}
          </span>
          <span className="block">{`})`}</span>
        </pre>
        <div
          aria-live="polite"
          className={cn(
            "mt-3 flex items-center gap-2 font-mono text-xs",
            sent
              ? "text-emerald-600 dark:text-emerald-400"
              : "text-foreground/35"
          )}
        >
          <span aria-hidden="true">{sent ? "✓" : "○"}</span>
          <span>{sent ? "passes" : "awaiting input"}</span>
        </div>
      </Panel>

      <Panel label="Database">
        {sent ? (
          <pre
            className={cn(
              "font-mono text-xs leading-6 transition-colors",
              deleted
                ? "text-foreground/30 line-through decoration-red-500/70 dark:decoration-red-400/70"
                : "text-foreground/80"
            )}
          >
            <span className="block text-foreground/55">
              {"profiles[id="}
              {PROFILE_ID}
              {"]"}
            </span>
            <span className="block">{`{`}</span>
            <span className="block">{`  name: "${PROFILE_NAME}",`}</span>
            <span className="block">
              {"  createdAt: "}
              <span className="text-amber-700 dark:text-amber-400">
                {COERCED_CREATED_AT}
              </span>
            </span>
            <span className="block">{`}`}</span>
          </pre>
        ) : (
          <pre className="font-mono text-foreground/55 text-xs leading-6">
            <span className="block">
              {"profiles[id="}
              {PROFILE_ID}
              {"]"}
            </span>
            <span className="block">{`{`}</span>
            <span className="block">{`  name: "${PROFILE_NAME}",`}</span>
            <span className="block">
              {"  createdAt: "}
              <span className="text-foreground/55">{ORIGINAL_CREATED_AT}</span>
            </span>
            <span className="block">{`}`}</span>
          </pre>
        )}
      </Panel>
    </div>
  );
}

function Panel({
  children,
  label,
}: {
  children: React.ReactNode;
  label: string;
}) {
  return (
    <div className="rounded-2xl border border-border bg-card/40 p-4 shadow-sm sm:p-5">
      <p className="mb-3 font-medium font-mono text-[0.65rem] text-foreground/50 uppercase tracking-[0.2em]">
        {label}
      </p>
      {children}
    </div>
  );
}

